-- ═══════════════════════════════════════════════════════════════
-- Import Customers & Suppliers from Excel files
-- Supports 3 party types: customer, supplier, customerSupplier
-- Idempotent / safe to re-run (uses ON CONFLICT DO NOTHING)
-- ═══════════════════════════════════════════════════════════════

-- ─── Suppliers ────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;

-- ─── Customers ────────────────────────────────────────────────
ON CONFLICT (id) DO NOTHING;
